  ('EMOM', 'emom', 'EMOM', 'Every Minute On the Minute: athletes complete assigned work at the start of each minute and rest for the remaining time.', 'A structured density format that controls pace, keeps groups organized, and builds repeatability when the work fits inside each minute.', 'Do your assigned work when the minute starts, then rest until the next minute.', 'repeatability and structured density', ARRAY['pacing', 'strength endurance', 'work capacity'], 'emom', 'sustained_capacity', ARRAY['capacity', 'resilience', 'sustained_capacity'], ARRAY['output', 'movement_intelligence'], ARRAY['mixed', 'local_muscular_endurance'], '{"fatigue_intentional":true,"fatigue_level":"moderate","technical_risk_under_fatigue":"moderate","impact_risk_under_fatigue":"depends_on_exercises","grip_risk_under_fatigue":"depends_on_exercises"}', 'recommended', 'EMOM means Every Minute On the Minute. The athlete starts a task at the beginning of each minute. Any time left in the minute becomes rest.', 'EMOM builds repeatability, pacing, and density because athletes must complete quality work repeatedly while managing rest.', 'Use late in the session for Sustained Capacity or during Capacity when loads are moderate and quality remains high.', 'Do not use EMOM for advanced skill learning, max sprinting, max plyometrics, or technical tumbling under fatigue.', ARRAY['prescribing too much work so no rest remains', 'using movements that are too technical', 'turning every EMOM into punishment', 'ignoring form breakdown'], '{"default_prescription":{"beginner":{"minutes":8,"work_target_seconds":20,"rest_target_seconds":40,"rpe":"5-6"},"intermediate":{"minutes":12,"work_target_seconds":25,"rest_target_seconds":35,"rpe":"6-7"},"advanced":{"minutes":16,"work_target_seconds":30,"rest_target_seconds":30,"rpe":"7-8"}},"work_rest_options":["1 movement EMOM","alternating EMOM","4-station EMOM"],"typical_total_duration_minutes":[8,10,12,16,20],"recommended_density":"Work should usually take 20-35 secon